import collections

def kosaraju(graph):
    finish_order = []
    visited = set()

    all_nodes = set(graph.keys())
    for u_list in graph.values():
        all_nodes.update(u_list)

    def dfs1(node):
        visited.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                dfs1(neighbor)
        finish_order.append(node)

    for node in all_nodes:
        if node not in visited:
            dfs1(node)

    transposed_graph = collections.defaultdict(list)
    for u, neighbors in graph.items():
        for v in neighbors:
            transposed_graph[v].append(u)

    sccs = []
    visited.clear()

    def dfs2(node, current_scc):
        visited.add(node)
        current_scc.append(node)
        for neighbor in transposed_graph.get(node, []):
            if neighbor not in visited:
                dfs2(neighbor, current_scc)

    for node in reversed(finish_order):
        if node not in visited:
            current_scc = []
            dfs2(node, current_scc)
            sccs.append(current_scc)

    return sccs
